2 Section 1 : dplyr avancé

2.1 Exercice 1.1 — mutate() avec case_when()
case_when() permet de créer une variable catégorielle à partir de conditions multiples, comme un if/else appliqué à toute une colonne.
En 2007, créez une colonne cat_richesse qui classe chaque pays en :

"Riche" si gdpPercap &gt;= 20000
"Intermédiaire" si gdpPercap &gt;= 5000
"Pauvre" pour tous les autres

Ensuite, comptez combien de pays appartiennent à chaque catégorie par continent.

gapminder |&gt;
  filter(???) |&gt;
  mutate(
    cat_richesse = case_when(
      gdpPercap &gt;= ??? ~ "Riche",
      gdpPercap &gt;= ??? ~ "Intermédiaire",
      TRUE             ~ "Pauvre"
    )
  ) |&gt;
  count(???, ???)







Correction






gapminder |&gt;
  filter(year == 2007) |&gt;
  mutate(
    cat_richesse = case_when(
      gdpPercap &gt;= 20000 ~ "Riche",
      gdpPercap &gt;= 5000  ~ "Intermédiaire",
      TRUE               ~ "Pauvre"
    )
  ) |&gt;
  count(continent, cat_richesse)

À observer : Tous les pays d’Océanie et d’Europe sont “Riches” ou “Intermédiaires”. L’Afrique est quasi entièrement “Pauvre” selon ce critère.






2.2 Exercice 1.2 — summarise() avancé
Calculez, pour chaque continent en 2007, les statistiques suivantes sur l’espérance de vie : - la moyenne (mean) - la médiane (median) - l’écart-type (sd) - le minimum et le maximum - le nombre de pays (n())
Triez du continent avec la plus haute espérance de vie moyenne au plus bas.

gapminder |&gt;
  filter(???) |&gt;
  group_by(???) |&gt;
  summarise(
    moy    = ???,
    median = ???,
    ecart  = ???,
    min    = ???,
    max    = ???,
    n      = ???
  ) |&gt;
  arrange(???)







Correction






gapminder |&gt;
  filter(year == 2007) |&gt;
  group_by(continent) |&gt;
  summarise(
    moy    = mean(lifeExp),
    median = median(lifeExp),
    ecart  = sd(lifeExp),
    min    = min(lifeExp),
    max    = max(lifeExp),
    n      = n()
  ) |&gt;
  arrange(desc(moy))







2.3 Exercice 1.3 — left_join() : fusionner deux tableaux
left_join() fusionne deux data frames à partir d’une colonne commune.
Créez ce tableau de régions géopolitiques :

regions &lt;- tibble(
  continent = c("Africa", "Americas", "Asia", "Europe", "Oceania"),
  region_onu = c("Global South", "Americas", "Asia-Pacific",
                 "Western nations", "Asia-Pacific")
)

Ensuite :

Fusionnez regions avec gapminder (année 2007 seulement)
Calculez l’espérance de vie moyenne par region_onu
Affichez le résultat trié


gapminder |&gt;
  filter(???) |&gt;
  left_join(???, by = "continent") |&gt;
  group_by(???) |&gt;
  summarise(esperance_moy = mean(???)) |&gt;
  arrange(???)







Correction






regions &lt;- tibble(
  continent  = c("Africa", "Americas", "Asia", "Europe", "Oceania"),
  region_onu = c("Global South", "Americas", "Asia-Pacific",
                 "Western nations", "Asia-Pacific")
)

gapminder |&gt;
  filter(year == 2007) |&gt;
  left_join(regions, by = "continent") |&gt;
  group_by(region_onu) |&gt;
  summarise(esperance_moy = mean(lifeExp)) |&gt;
  arrange(desc(esperance_moy))

Le pipe : |&gt;
Le pipe enchaîne les opérations. Lisez-le comme « puis ».

# Sans pipe
arrange(filter(gapminder, year == 2007), desc(lifeExp))

# Avec pipe — bien plus lisible
gapminder |&gt;
  filter(year == 2007) |&gt;
  arrange(desc(lifeExp))

Raccourci : Ctrl + Shift + M (Win) / Cmd + Shift + M (Mac)

mutate() avec case_when()
case_when() crée une variable catégorielle à partir de conditions — comme un if/else vectorisé.

gapminder |&gt;
  filter(year == 2007) |&gt;
  mutate(
    categorie_vie = case_when(
      lifeExp &gt;= 75 ~ "Élevée (75+)",
      lifeExp &gt;= 60 ~ "Moyenne (60–75)",
      TRUE          ~ "Faible (&lt; 60)"    # tous les autres cas
    )
  ) |&gt;
  count(continent, categorie_vie)


Logique : R évalue les conditions dans l’ordre — dès qu’une est TRUE, il assigne la valeur.

Résumer de façon avancée

# Plusieurs statistiques en même temps
gapminder |&gt;
  filter(year == 2007) |&gt;
  group_by(continent) |&gt;
  summarise(
    esperance_moy    = mean(lifeExp),
    esperance_median = median(lifeExp),
    esperance_min    = min(lifeExp),
    esperance_max    = max(lifeExp),
    nb_pays          = n()
  ) |&gt;
  arrange(desc(esperance_moy))

left_join() : fusionner deux tableaux
left_join() combine deux data frames sur une colonne commune — comme RECHERCHEV dans Excel, mais mieux.

# Créer un tableau de codes de continents
codes_continent &lt;- tibble(
  continent = c("Africa", "Americas", "Asia", "Europe", "Oceania"),
  code      = c("AF", "AM", "AS", "EU", "OC")
)

# Fusionner avec gapminder
gapminder |&gt;
  filter(year == 2007) |&gt;
  left_join(codes_continent, by = "continent") |&gt;
  select(country, continent, code, lifeExp)


Règle : toutes les lignes du tableau de gauche sont conservées.

Graphique en barres : geom_col()

gapminder |&gt;
  filter(year == 2007) |&gt;
  group_by(continent) |&gt;
  summarise(esperance_moy = mean(lifeExp)) |&gt;
  ggplot(aes(x = reorder(continent, esperance_moy),
             y = esperance_moy,
             fill = continent)) +
  geom_col(show.legend = FALSE) +
  coord_flip() +                  # barres horizontales
  labs(
    title = "Espérance de vie moyenne par continent (2007)",
    x     = "Continent",
    y     = "Espérance de vie (années)"
  ) +
  theme_minimal()

Calculer le sentiment par répondant

# Joindre les mots avec le lexique
sentiment_par_auteur &lt;- mots_propres |&gt;
  inner_join(bing, by = c("mot" = "word")) |&gt;
  count(auteur, sentiment) |&gt;
  pivot_wider(
    names_from  = sentiment,
    values_from = n,
    values_fill = 0
  ) |&gt;
  mutate(score_net = positive - negative)

sentiment_par_auteur

Pour aller plus loin en analyse textuelle

# Fréquence TF-IDF (mots distinctifs par groupe)
mots_propres |&gt;
  count(auteur, mot) |&gt;
  bind_tf_idf(mot, auteur, n) |&gt;
  arrange(desc(tf_idf))

# Bigrammes (paires de mots consécutifs)
reponses |&gt;
  unnest_tokens(bigram, texte, token = "ngrams", n = 2) |&gt;
  count(bigram, sort = TRUE)

